    sessionIdleTimeoutMs: opts.limits?.sessionIdleTimeoutMs ?? 30 * 60000,
    spawnTimeoutMs: opts.limits?.spawnTimeoutMs ?? 15000,
    promptTimeoutMs: opts.limits?.promptTimeoutMs ?? 120000,
    loginTimeoutMs: login.timeoutMs
